<template>
    <div style="height: 600px;">
        <div id="viewer" style="width:100%;min-height:80vh;margin-bottom: 0%;height: auto;min-height: 650px;"></div>
    </div>
    
</template>

<script>
export default {
    props:{
        reportPath:null,
        parameter:null
    },
    data: function () {
        return {
            Token:null,
            reporturl:''
        }
    },

    created:function(){
     this.Token= this.GetUserInfo.Token;

    },
    // mounted() {
    //     debugger;
    //     var vm = this;
    //     vm.reporturl=process.env.VUE_APP_REPORT_SERVER_URL
    //     console.log(vm.parameter);
    //     setTimeout(function () {
    //         $("#viewer").boldReportViewer({
    //             reportServiceUrl: process.env.VUE_APP_TALYGEN_REPORT_API_URL + '/ReportViewer',
    //             reportPath: vm.reportPath,
    //             processingMode:"Remote", 
    //             parameters: vm.parameter,
    //             reportServerUrl: vm.reporturl,
    //             ajaxBeforeLoad: vm.setReportToken,
    //         }); 
    //    }, 2000);
    // },

    mounted() {
      this.reporturl = process.env.VUE_APP_REPORT_SERVER_URL;
      console.log('Report Parameters:', this.parameter);
      
      // Initialize the BoldReportViewer after the component is mounted
      this.initializeReportViewer();
    },

// methods: {
//     setReportToken:function(args){
//         args.headers.push({ Key: 'content-type', Value: 'application/json;charset=UTF-8' });
//         args.headers.push({ Key: 'Authorization', Value: `Bearer ${this.Token}` });

//     }
// }

methods: {
      // Method to initialize the report viewer
      initializeReportViewer() {
        const vm = this;
        //debugger;
        // Initialize the BoldReportViewer with configuration settings
        $("#viewer").boldReportViewer({
            
          reportServiceUrl: process.env.VUE_APP_TALYGEN_REPORT_API_URL + '/ReportViewer',
          reportPath: vm.reportPath,
          processingMode: "Remote", // Ensure the report processing is done remotely
          parameters: vm.parameter, // Pass the parameters to the report
          reportServerUrl: vm.reporturl,
          ajaxBeforeLoad: vm.setReportToken, // Set the token for each report request
          exportSettings: {
            exportOptions: ej.ReportViewer.ExportOptions.Excel | ej.ReportViewer.ExportOptions.Pdf,
          },
          toolbarSettings: {
            showToolbar: true, // Ensure the toolbar is visible
            click: vm.onToolbarClick, // Bind the toolbar click method
            showTooltip: true, // Optional: Show tooltips for toolbar items
            autoHide: true, // Optional: Auto-hide horizontal toolbar when idle
          },
        });
  
        // Manually trigger a check after the report viewer is initialized to ensure the toolbar click is bound
        setTimeout(() => {
          console.log('Checking if the export functionality is bound...');
          const viewerInstance = $("#viewer").data('boldReportViewer');
          if (viewerInstance) {
            console.log('Bold Report Viewer Initialized:', viewerInstance);
          }
        }, 1000);
      },
  
      // This function sets the authorization token before each report load
      setReportToken(args) {
        args.headers.push({ Key: 'content-type', Value: 'application/json;charset=UTF-8' });
        args.headers.push({ Key: 'Authorization', Value: `Bearer ${this.Token}` });
      },
  
      // Method to handle toolbar item clicks (specifically for the 'Export' button)
      onToolbarClick(event) {
        debugger;
        console.log('Toolbar button clicked:', event); // This log should now be triggered
  
        if (event.command === 'Export') {
          console.log('Export button clicked');
          this.handleExport(); // Call the method to handle export
        }
  
        // Handle other toolbar actions (e.g., Print, Refresh, etc.)
        switch (event.command) {
          case 'Print':
            console.log('Print button clicked');
            break;
          case 'Refresh':
            console.log('Refresh button clicked');
            break;
          default:
            console.log('Other button clicked');
        }
      },
  
      // Function to manually handle the export action
      handleExport() {
        console.log('Manually triggering export...');
  
        // Try to manually trigger the export if the report viewer has been initialized
        const viewerInstance = $("#viewer").data('boldReportViewer');
        if (viewerInstance) {
          // Manually trigger the export
          viewerInstance.exportReport();
          console.log('Export triggered');
        } else {
          console.error('Report viewer instance not found');
        }
      }
    },

}
</script>




