<template lang="en">
    <div>
        <loader :isVisible="isLoading"></loader>
        <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
        <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
    </div>
    </template>
    
        
    <script>
    import DataServices from "../../services/DataService";
    import ReportViewer from './ReportViewer.vue';
    export default {
        components: {
            ReportViewer
        },
        data() {
            return {
                reportPath: null,
                parameter: [],
                FindalLocationArray: [],
                isLoading: false,
                FormSchema: [{
                        layoutType: "triple",
                        Data: [{
                                astype: "MultiSelectField",
                                label: this.$t("Users"),
                                name: "Users",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Users'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    // onChange: this.onChangeDropdown,
                                    // onRemove: this.removeRecord,
                                },
                            },
                            
                            {
                                astype: "MultiSelectField",
                                label: this.$t("The Approver"),
                                name: "Approver",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t(' Approver'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    // onChange: this.onChangeDropdown,
                                    // onRemove: this.removeRecord,
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Approval Group"),
                                name: "ApprovalGroup",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Approval Group'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    // onChange: this.onChangeDropdown,
                                    // onRemove: this.removeRecord,
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Department"),
                                name: "Department",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Department'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    // onChange: this.onChangeDropdown,
                                    // onRemove: this.removeRecord,
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Designation"),
                                name: "Designation",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Designation'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    // onChange: this.onChangeDropdown,
                                    // onRemove: this.removeRecord,
                                },
                            },
                        ],
                    },
                    
                ],
                buttons: [{
                        type: "submit",
                        class: "btn btn-success",
                        text: "<i class='fa fa-search pr-2'></i>Search",
                    },
                    {
                        type: "button",
                        class: "btn btn-danger",
                        text: "<i class='fa fa-close pr-2'></i>Clear all",
                        onClick: this.ClearAll
                    },
                ],
                DataLoaded: 0,
            };
        },
        created: async function () {
            var vm = this;
            vm.DataLoaded = 1;
            vm.userId = vm.GetUserInfo.ID;
            vm.companyId = vm.GetUserInfo.CompanyId;
            await vm.GetUserList();
            await vm.GetApproverList();
            await vm.GetApprovalGroupList();
            await vm.BindDepartment();
            await vm.BindDesignation();
        },
        methods:{

            ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[0].Data[3].value = '';
            (vm.FormSchema)[0].Data[4].value = '';
           
        },
            onSubmit(e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
            var vm = this;
            vm.isLoading=true;
            vm.reportPath = '';      
            vm.parameter=[]; 
            let myObj = {
                reportName: "leaveapprovedbyapproverreport",
                approverIds:  e.Approver.length > 0 ? e.Approver.map(item => item.value).join(",") : '',
                ApprovalGroupIds:  e.ApprovalGroup.length > 0 ? e.ApprovalGroup.map(item => item.value).join(",") : '',
                DepartmentIds:  e.Department.length > 0 ? e.Department.map(item => item.value).join(",") : '',
                DesignationIds:  e.Designation.length > 0 ? e.Designation.map(item => item.value).join(",") : '',
                userIds:  e.Users.length > 0 ? e.Users.map(item => item.value).join(",") : '',
            }
            var postString = JSON.stringify(myObj);   
             DataServices.ReportMain(postString).then(function (response) {
                debugger;
                vm.reportPath = response.data.ReportPath;
                vm.parameter = response.data.parameters;
            })
            vm.isLoading=false;
        },
            GetUserList:async function () {
                debugger;
            var vm = this;
            var params = `projectId=&userType=&isActive=1&ticketId=0&moduleName=HRReport`;
            DataServices.GetUserList(params).then((response) => {
                if (response.data != '') {
                    vm.EmployeeData = response.data;
                    vm.EmployeeData.forEach(item => {
                        vm.FormSchema[0].Data[0].config.options.push({
                            name: item.UserName,
                            value: item.UserId
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },  
        BindDepartment: async function () {
            var vm = this;
            var url = `id=&moduleName=HIRINGReport&type=DEPARTMENT&search=&refId`;
            await DataServices.GetDDLData(url).then((response) => {
                if (response.data.DATA.length > 0) {
                    var DepartmentData = response.data.DATA;
                    DepartmentData.forEach(element => {
                        var Obj = {
                            name: element.name,
                            value: element.value
                        }
                        vm.FormSchema[0].Data[3].config.options.push(Obj);
                    });  
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        BindDesignation: async function () {
            var vm = this;
            var url = `id=&moduleName=HIRINGReport&type=USER_DESIGNATION&search=&refId`;
            await DataServices.GetDDLData(url).then((response) => {
                if (response.data.DATA.length > 0) {
                    var DepartmentData = response.data.DATA;
                    DepartmentData.forEach(element => {
                        var Obj = {
                            name: element.name,
                            value: element.value
                        }
                        vm.FormSchema[0].Data[4].config.options.push(Obj);
                    });  
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }   
            });
        }, 
        GetApproverList:async function () {
                debugger;
            var vm = this;
            var params = `userId=${vm.userId}&companyId=${vm.companyId}&aprovalType=4`;
            DataServices.GetApprover(params).then((response) => {
                if (response.data != '') {
                    debugger;
                    vm.EmployeeData = response.data;
                    vm.EmployeeData.forEach(item => {
                        vm.FormSchema[0].Data[1].config.options.push({
                            name: item.USER_NAME,
                            value: item.USER_ID
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },
        GetApprovalGroupList:async function () {
                debugger;
            var vm = this;
            var params = `userId=${vm.userId}&companyId=${vm.companyId}&aprovalType=4`;
            DataServices.GetApprovalGroup(params).then((response) => {
                if (response.data != '') {
                    debugger;
                    vm.EmployeeData = response.data;
                    vm.EmployeeData.forEach(item => {
                        vm.FormSchema[0].Data[2].config.options.push({
                            name: item.APPROVAL_GROUP_NAME,
                            value: item.APPROVAL_GROUP_ID
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
         }
        }
    };
    </script>
    